import os, re
from pathlib import Path

inbox = Path("/opt/docker/appdata/obsidian-jellybase/vault/OB_v2/Archive/personal/Evernote/inbox.0")
vault = Path("/opt/docker/appdata/obsidian-jellybase/vault/OB_v2")

PRINT_PATTERNS = re.compile(
    r'3d.?print|thingiverse|printables\.com|gridfinity|ender.?3|klipper|'
    r'filament|vise|workbench|spool|nozzle|slicer|prusa|cults3d|'
    r'lack.enclosure|bench.dog|openscad|gcode|marlin|bltouch|'
    r'gridfinity|fidget|articul|paracord|clamp|vice|workbench|bench|'
    r'lamp|vase|pegboard|modular.mount|cable.holder|solde',
    re.IGNORECASE
)

URL_RE = re.compile(r'https?://[^\s\)\]"\'<>]+')
MODEL_SITES = ['thingiverse.com/thing:', 'printables.com/model', 'cults3d.com/en/3d-model',
               'myminifactory.com/object', 'thangs.com', 'makerworld.com/en/models']

def get_best_url(content, name):
    urls = URL_RE.findall(content)
    # 1. Direct model URL
    for u in urls:
        if any(s in u for s in MODEL_SITES):
            return u.rstrip('/')
    # 2. Thingiverse thing page (less specific patterns)
    for u in urls:
        if 'thingiverse.com/thing:' in u:
            return u.split('/likes')[0].split('/make')[0].split('/report')[0].rstrip('/')
    # 3. Any printables/cults
    for u in urls:
        if any(s in u for s in ['printables.com', 'cults3d.com', 'myminifactory.com']):
            return u.rstrip('/')
    return None

# Categories for organisation
CATEGORIES = {
    'Ender / Klipper Setup': r'ender|klipper|firmware|slicer|bltouch|bed.level|z.offset|calibrat',
    'Gridfinity': r'gridfinity',
    'Workbench & Tools': r'workbench|vise|vice|clamp|bench|ruler|square|depth.gauge|hex.key|t.handle|handle',
    'Storage & Organisation': r'spool|filament.guide|filament.silo|storage|box|bin|holder|organis|hanger|pegboard|cable',
    'Lamps & Decor': r'lamp|vase|voronoi|wave|kinetic|art|sculpture|flower|spiral',
    'Useful Prints': r'fidget|keychain|door.stop|pill|cap|plug|hanger|clip|stand|mount|bracket',
    'Reference & Guides': r'guide|tips|how.to|upgrade|setup|install|macro|all3dp',
}

entries = {}  # category -> [(name, url)]
for cat in CATEGORIES:
    entries[cat] = []
uncategorised = []

for f in sorted(inbox.glob("*.md")):
    name = f.stem
    # Skip pure Printables page dumps (no real model)
    if re.match(r'^Printables(\.\d+)?$', name):
        continue
    if not PRINT_PATTERNS.search(name):
        continue
    # Skip duplicates (.1, .2 variants)
    if re.search(r'\.\d+$', name):
        base = re.sub(r'\.\d+$', '', name)
        if (inbox / (base + '.md')).exists():
            continue

    content = f.read_text(errors='ignore')
    url = get_best_url(content, name)

    # Categorise
    placed = False
    for cat, pat in CATEGORIES.items():
        if re.search(pat, name, re.IGNORECASE):
            entries[cat].append((name, url))
            placed = True
            break
    if not placed:
        uncategorised.append((name, url))

# Build the markdown
lines = [
    "# 3D Printing — Master Download List",
    "",
    "> Compiled from Evernote archive. Links to Thingiverse, Printables, Cults3D, MyMiniFactory.",
    f"> Generated: 2026-06-06",
    "",
]

total = 0
for cat, items in entries.items():
    if not items:
        continue
    lines.append(f"## {cat}")
    lines.append("")
    for name, url in sorted(items):
        clean = re.sub(r'\s+', ' ', name).strip()
        if url:
            lines.append(f"- [{clean}]({url})")
        else:
            lines.append(f"- {clean}")
        total += 1
    lines.append("")

if uncategorised:
    lines.append("## Misc")
    lines.append("")
    for name, url in sorted(uncategorised):
        clean = re.sub(r'\s+', ' ', name).strip()
        if url:
            lines.append(f"- [{clean}]({url})")
        else:
            lines.append(f"- {clean}")
        total += 1
    lines.append("")

lines.append(f"---")
lines.append(f"*{total} items*")

out = vault / "03 Spaces" / "3D Printing — Master List.md"
out.write_text('\n'.join(lines))
print(f"Written: {out}")
print(f"Total items: {total}")
for cat, items in entries.items():
    if items:
        print(f"  {cat}: {len(items)}")
if uncategorised:
    print(f"  Misc: {len(uncategorised)}")
